<script setup lang="ts">
import { computed, reactive } from 'vue'
import { useFullscreenElement } from '../lib/useFullscreen'
import { buildAiPcPenetrationSensitivityRows, buildPcShipmentSensitivityRows, calculatePcDramDemand, formatCapacity, formatNumber, listPcDramScenarioPresets, type PcDramDemandInput } from '../lib/pcDramDemand'
const input = reactive<PcDramDemandInput>({ pcShipmentsMillion: 250, aiPcPenetrationPercent: 20, nonAiDramGbPerPc: 8, aiPcDramGbPerPc: 16 })
const { targetRef: simulatorRoot, isFullscreen, toggleFullscreen } = useFullscreenElement()
const presets = listPcDramScenarioPresets()
function applyPreset(presetInput: PcDramDemandInput) { Object.assign(input, presetInput) }
const result = computed(() => calculatePcDramDemand(input))
const shipmentSensitivityRows = computed(() => buildPcShipmentSensitivityRows(input, [-20, -10, 0, 10, 20]))
const aiPcPenetrationRows = computed(() => buildAiPcPenetrationSensitivityRows(input, [0, 10, 20, 30, 50]))
const maxDemand = computed(() => Math.max(...aiPcPenetrationRows.value.map((row) => row.result.totalDramGb)))
const currentScenarioLabel = computed(() => presets.find((preset) => JSON.stringify(preset.input) === JSON.stringify({ ...input }))?.label ?? 'Custom user scenario')
</script>
<template><section ref="simulatorRoot" class="simulator-card" style="--sim-a:rgba(14,165,233,.10);--sim-b:rgba(132,204,22,.08)" :class="{ 'is-fullscreen': isFullscreen }"><div class="simulator-header"><div><p class="eyebrow">Assumption Workbench · PC DRAM</p><h2>PC DRAM 수요</h2></div><div><p class="formula">Demand = PC Shipments × Weighted Avg. DRAM/PC</p><button class="simulator-fullscreen-toggle" type="button" @click="toggleFullscreen">{{ isFullscreen ? '전체화면 종료' : '전체화면' }}</button></div></div><div class="simulator-workbench"><div class="workbench-main"><details class="preset-comparison foldable-card" open><summary class="foldable-card-summary">Scenario presets</summary><table><thead><tr><th>Preset</th><th>AI PC</th><th>Content</th><th>Confidence</th><th></th></tr></thead><tbody><tr v-for="preset in presets" :key="preset.id"><td><strong>{{ preset.label }}</strong><br/><small>{{ preset.description }}</small></td><td>{{ preset.input.aiPcPenetrationPercent }}%</td><td>{{ preset.input.nonAiDramGbPerPc }}/{{ preset.input.aiPcDramGbPerPc }} GB</td><td class="preset-source-row"><b class="confidence-badge">{{ preset.confidence }}</b> · {{ preset.sourceRefs.length }} refs</td><td><button class="apply-button" type="button" @click="applyPreset(preset.input)">Apply scenario</button></td></tr></tbody></table></details><details class="panel foldable-card" open><summary class="foldable-card-summary">Assumptions</summary><div class="control-grid"><article class="control-row"><label>PC shipments <input v-model.number="input.pcShipmentsMillion" type="number" min="0" step="5" /></label><input v-model.number="input.pcShipmentsMillion" type="range" min="100" max="400" step="5" /><div class="quick-chips"><button class="quick-chip" @click="input.pcShipmentsMillion = 200">200M</button><button class="quick-chip" @click="input.pcShipmentsMillion = 250">250M</button><button class="quick-chip" @click="input.pcShipmentsMillion = 300">300M</button></div><p class="impact">Impact: unit demand scales total DRAM linearly.</p><span class="source-pill">User input</span></article><article class="control-row"><label>AI PC penetration <input v-model.number="input.aiPcPenetrationPercent" type="number" min="0" max="100" /></label><input v-model.number="input.aiPcPenetrationPercent" type="range" min="0" max="100" step="1" /><div class="quick-chips"><button class="quick-chip" @click="input.aiPcPenetrationPercent = 10">10%</button><button class="quick-chip" @click="input.aiPcPenetrationPercent = 30">30%</button><button class="quick-chip" @click="input.aiPcPenetrationPercent = 50">50%</button></div><p class="impact">Impact: shifts mix toward higher DRAM content PCs.</p><span class="source-pill">Adoption assumption</span></article><article class="control-row"><label>Non-AI DRAM <input v-model.number="input.nonAiDramGbPerPc" type="number" min="0" /></label><input v-model.number="input.nonAiDramGbPerPc" type="range" min="4" max="32" step="1" /><div class="quick-chips"><button class="quick-chip" @click="input.nonAiDramGbPerPc = 8">8GB</button><button class="quick-chip" @click="input.nonAiDramGbPerPc = 16">16GB</button></div><p class="impact">Impact: installed base floor.</p><span class="source-pill">Content anchor</span></article><article class="control-row"><label>AI PC DRAM <input v-model.number="input.aiPcDramGbPerPc" type="number" min="0" /></label><input v-model.number="input.aiPcDramGbPerPc" type="range" min="8" max="64" step="1" /><div class="quick-chips"><button class="quick-chip" @click="input.aiPcDramGbPerPc = 16">16GB</button><button class="quick-chip" @click="input.aiPcDramGbPerPc = 24">24GB</button><button class="quick-chip" @click="input.aiPcDramGbPerPc = 32">32GB</button></div><p class="impact">Impact: AI PC content uplift.</p><span class="source-pill">Source-backed candidate</span></article></div></details><details class="sensitivity-bars foldable-card" open><summary class="foldable-card-summary">Visual sensitivity</summary><div v-for="row in aiPcPenetrationRows" :key="row.aiPcPenetrationPercent" class="bar-row"><span>{{ row.aiPcPenetrationPercent }}% AI PC</span><div class="bar-track"><div class="bar-fill" :style="{ width: `${(row.result.totalDramGb / maxDemand) * 100}%` }"></div></div><strong>{{ formatCapacity(row.result.totalDramGb) }}</strong></div><details class="table-wrap"><summary>Exact values</summary><table><tbody><tr v-for="row in shipmentSensitivityRows" :key="row.changePercent"><td>{{ row.changePercent }}% units</td><td>{{ formatCapacity(row.result.totalDramGb) }}</td></tr></tbody></table></details></details></div><aside class="result-rail"><div class="sticky-result-panel"><span class="primary-result-label">Primary result</span><strong class="primary-result-value">{{ formatNumber(result.totalDramEb, 4) }} EB</strong><p class="primary-result-note">{{ formatCapacity(result.totalDramGb) }} · {{ currentScenarioLabel }}</p><div class="result-grid"><article><span>AI / Non-AI units</span><strong>{{ formatNumber(result.aiPcUnitsMillion, 1) }}M / {{ formatNumber(result.nonAiPcUnitsMillion, 1) }}M</strong></article><article><span>Avg DRAM</span><strong>{{ formatNumber(result.weightedAverageDramGb, 2) }} GB</strong></article></div><p class="note">Primary result updates as assumptions move.</p></div></aside></div></section></template>
